// Reshape input to match original node expectations
// Original nodes expect: .body (webhook metadata), .data (transcript text)
const input = $input.first().json;
const transcript = input.transcript || {};
return [{json: {
  body: {
    meeting_name: input.meeting_name || '',
    participants: input.participants || '',
    date: input.date || '',
    start_time: input.start_time || '',
    file_id: input.file_id || '',
    bot_token: input.bot_token || ''
  },
  data: transcript.data || transcript.text || '',
  segments: transcript.segments || [],
  language: transcript.language || 'fi',
  // Keep raw transcript for Return Results
  _transcript: transcript,
  _meeting_name: input.meeting_name,
  _participants: input.participants,
  _date: input.date,
  _start_time: input.start_time
}}];

// ── Free VRAM: unload idle models before LLM-heavy pipeline ──
try {
    await this.helpers.httpRequest({
        method: 'POST', url: 'http://host.docker.internal:11434/api/generate',
        body: {model: 'qwen2.5vl:7b', keep_alive: 0}, json: true
    });
} catch(e) { /* model may not be loaded — ignore */ }
try {
    await this.helpers.httpRequest({
        method: 'POST', url: 'http://host.docker.internal:11434/api/generate',
        body: {model: 'nemotron-mini', keep_alive: 0}, json: true
    });
} catch(e) { /* model may not be loaded — ignore */ }

const webhookBody = $('Set Metadata').first().json.body;
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const rawTranscript = $('Set Metadata').first().json.data || '';

// Full transcript for speaker ID — even 83-min meetings (72k chars) fit in 32k tokens
// Prompt eval dominates (~220s), generation is tiny (~50 tokens)
const MAX_CHARS = 75000;
const transcript = rawTranscript.length > MAX_CHARS
    ? rawTranscript.substring(0, MAX_CHARS) + '\n\n[... truncated ...]'
    : rawTranscript;

const systemPrompt = `You identify speakers in a meeting transcript.

RULES:
- Speakers already labeled with a real name (e.g. [Petri], [Mikko]) are biometrically verified. Do NOT change them. Map them to themselves.
- Only identify unresolved labels: [SPEAKER_00], [SPEAKER_01], [Unknown], etc.
- Look for self-introductions ("I'm Johanna"), direct address ("Thanks Petri"), role signals.
- Cross-reference with known participants list.
- If you cannot identify a speaker, keep the original label.

- Names MUST be in Lastname Firstname order (family name first). If participants say "Johanna Aivio", map to "Aivio Johanna". If only a first name is known, keep just the first name.

OUTPUT FORMAT (strict JSON, no markdown, no explanation):
{"speaker_map": {"SPEAKER_00": "Lastname Firstname", "SPEAKER_01": "SPEAKER_01"}}`;

const userMsg = `Known participants: ${participantStr}\n\nTranscript:\n${transcript}`;

return [{ json: {
    body: JSON.stringify({
        model: 'qwen3.5:27b-32k',
        stream: false,
        think: false,
        num_ctx: 32768,
        system: systemPrompt,
        prompt: userMsg
    }),
    participantStr: participantStr,
    rawTranscript: rawTranscript
} }];

const rawTranscript = $('Set Metadata').first().json.data || '';

// ── safeParseJSON: strips think tokens, fences, preamble text ──
function safeParseJSON(raw) {
    let s = (raw || '').trim();
    // Strip <think>...</think> blocks (qwen reasoning tokens)
    s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    // Strip markdown code fences
    s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?\s*```\s*$/i, '');
    s = s.trim();
    // Find first { to last }
    const first = s.indexOf('{');
    const last = s.lastIndexOf('}');
    if (first === -1 || last === -1 || last <= first) {
        return { ok: false, data: null, error: 'No JSON object found', raw: raw };
    }
    s = s.substring(first, last + 1);
    try {
        return { ok: true, data: JSON.parse(s), error: null };
    } catch(e) {
        return { ok: false, data: null, error: e.message, raw: raw };
    }
}

// Parse speaker map from previous pass
let speakerMap = {};
const speakerResp = $input.first().json.response || '';
const parsed = safeParseJSON(speakerResp);
if (parsed.ok) {
    speakerMap = parsed.data.speaker_map || {};
} else if (speakerResp.trim()) {
    console.log('Speaker map parse failed: ' + (parsed.error || 'unknown'));
    console.log('Raw response: ' + speakerResp.substring(0, 500));
}

// Apply speaker names to transcript for better topic identification
let resolvedTranscript = rawTranscript;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll('[' + label + ']', '[' + name + ']');
}

// Full transcript — same budget as speaker ID pass
const MAX_CHARS = 75000;
const transcript = resolvedTranscript.length > MAX_CHARS
    ? resolvedTranscript.substring(0, MAX_CHARS) + '\n\n[... truncated ...]'
    : resolvedTranscript;

const systemPrompt = `You identify discussion topics in a meeting transcript.

For each topic, provide:
- A short descriptive name (3-8 words)
- The start and end timestamps (from the [HH:MM:SS] markers in the transcript)
- A one-sentence summary of the discussion

OUTPUT FORMAT (strict JSON, no markdown, no explanation):
{"topics": [
  {"name": "Project timeline update", "start": 0.0, "end": 180.5, "summary": "Discussed Q2 milestones"},
  {"name": "Budget review", "start": 181.0, "end": 450.2, "summary": "Reviewed cost overruns"}
]}

RULES:
- Output ONLY valid JSON. No markdown fences, no explanation.
- Every second of the transcript must be covered by exactly one topic.
- Topics must be in chronological order with no gaps.
- The LAST topic MUST have end: 999999 to capture all remaining content.
- Merge very short topics (< 30s) into adjacent ones.
- Typical meetings have 3-15 topics.`;

const userMsg = `Transcript:\n${transcript}`;

return [{ json: {
    body: JSON.stringify({
        model: 'qwen3.5:27b-32k',
        stream: false,
        think: false,
        num_ctx: 32768,
        system: systemPrompt,
        prompt: userMsg
    }),
    speakerMapRaw: speakerResp,
    speakerMap: speakerMap
} }];

const webhookBody = $('Set Metadata').first().json.body;
const date = webhookBody.date || new Date().toISOString().split('T')[0];
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const meetingName = webhookBody.meeting_name || '';
const startTime = webhookBody.start_time || '';
const endTime = webhookBody.end_time || '';
const context = webhookBody.context || '';
const transcriptFull = $('Set Metadata').first().json.data;

// ── safeParseJSON ──
function safeParseJSON(raw) {
    let s = (raw || '').trim();
    s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?\s*```\s*$/i, '');
    s = s.trim();
    const first = s.indexOf('{');
    const last = s.lastIndexOf('}');
    if (first === -1 || last === -1 || last <= first) {
        return { ok: false, data: null, error: 'No JSON object found', raw: raw };
    }
    s = s.substring(first, last + 1);
    try {
        return { ok: true, data: JSON.parse(s), error: null };
    } catch(e) {
        return { ok: false, data: null, error: e.message, raw: raw };
    }
}

// ── Deterministic topic segmentation fallback ──
// Segments by speaker turn patterns and time distribution
function deterministicTopics(transcript) {
    const lines = transcript.split('\n');
    const tsRegex = /\[(\d[\d:.]+)\s*(?:-->|->|\u2013|\u2014|-)\s*(\d[\d:.]+)\]/;
    const spkRegex = /\[([A-Z_]+\d*|[^\]]+)\]/;

    function timeToSec(t) {
        const p = t.trim().split(':');
        if (p.length === 3) return parseFloat(p[0])*3600 + parseFloat(p[1])*60 + parseFloat(p[2]);
        if (p.length === 2) return parseFloat(p[0])*60 + parseFloat(p[1]);
        return parseFloat(t) || 0;
    }

    // Parse all timestamped lines
    const entries = [];
    for (const line of lines) {
        const tsMatch = line.match(tsRegex);
        if (tsMatch) {
            const start = timeToSec(tsMatch[1]);
            const end = timeToSec(tsMatch[2]);
            const spkMatch = line.match(/\[(SPEAKER_\d+|[A-Z][a-zÀ-ÿ]+ [A-Z][a-zÀ-ÿ]+)\]/);
            const speaker = spkMatch ? spkMatch[1] : '';
            const text = line.replace(tsRegex, '').replace(/\[[^\]]*\]/g, '').trim();
            // Skip artifact lines (repeated single words like "Kiitos")
            if (text.length < 15 && /^(Kiitos[.!]*\s*)+$/i.test(text)) continue;
            entries.push({ start, end, speaker, text, line });
        }
    }

    if (entries.length === 0) return null;

    const totalStart = entries[0].start;
    const totalEnd = entries[entries.length - 1].end;
    const duration = totalEnd - totalStart;

    // Target 4-6 topics for a typical 30-60 min meeting
    const targetTopics = Math.max(3, Math.min(7, Math.round(duration / 300)));
    const targetLen = duration / targetTopics;

    // Find natural boundaries: score each entry as a potential boundary
    // Good boundaries: speaker changes after a gap, or after a long monologue
    const boundaries = [totalStart];
    let lastBoundary = totalStart;

    for (let i = 1; i < entries.length; i++) {
        const timeSinceBoundary = entries[i].start - lastBoundary;
        if (timeSinceBoundary < targetLen * 0.6) continue; // Too soon

        const gap = entries[i].start - entries[i-1].end;
        const speakerChange = entries[i].speaker !== entries[i-1].speaker;

        // Score this as a boundary point
        let score = 0;
        if (gap > 2) score += 2;
        if (gap > 5) score += 2;
        if (speakerChange) score += 3;
        if (timeSinceBoundary > targetLen * 0.8) score += 3;
        if (timeSinceBoundary > targetLen * 1.2) score += 5; // Overdue

        if (score >= 5) {
            boundaries.push(entries[i].start);
            lastBoundary = entries[i].start;
        }
    }
    boundaries.push(999999);

    // Build topics from boundaries
    const topics = [];
    for (let i = 0; i < boundaries.length - 1; i++) {
        const tStart = boundaries[i];
        const tEnd = boundaries[i + 1];
        // Get representative text for naming
        const topicEntries = entries.filter(e => e.start >= tStart && e.start < tEnd);
        const sampleText = topicEntries.slice(0, 5).map(e => e.text).join(' ');
        // Simple name from first substantial line
        const firstLine = topicEntries.find(e => e.text.length > 20);
        const name = firstLine
            ? firstLine.text.substring(0, 50).replace(/[.!?,;:]+$/, '') + '...'
            : `Topic ${i + 1}`;

        topics.push({
            name: `Segment ${i + 1}`,
            start: tStart,
            end: tEnd === 999999 ? 999999 : tEnd,
            summary: name
        });
    }

    return topics.length >= 2 ? topics : null;
}

// Speaker map from pass 1
const speakerMapData = $('Build Topic Segmentation Prompt').first().json.speakerMap || {};
const rawSpeakerMap = speakerMapData;

// Parse topics from pass 2 LLM response
let topics = [];
let topicsFallback = false;
const rawTopicResp = $input.first().json.response || '';
const parsed = safeParseJSON(rawTopicResp);
if (parsed.ok && parsed.data.topics && parsed.data.topics.length >= 2) {
    topics = parsed.data.topics;
} else {
    // LLM failed or returned single topic — try deterministic segmentation
    console.log('LLM topic segmentation failed or returned <2 topics, using deterministic fallback');
    if (parsed.error) console.log('Parse error: ' + parsed.error);
    const detTopics = deterministicTopics(transcriptFull);
    if (detTopics) {
        topics = detTopics;
        topicsFallback = true;
    } else {
        topics = [{name: 'Full Meeting', start: 0, end: 999999, summary: 'Complete meeting discussion'}];
        topicsFallback = true;
    }
}

// Validate speaker map against known participants
const knownLower = participantStr.toLowerCase().split(',').map(p => p.trim()).filter(Boolean);
const speakerMap = {};
for (const [label, name] of Object.entries(rawSpeakerMap)) {
    if (!label.startsWith('SPEAKER_') && label !== 'Unknown') {
        speakerMap[label] = name;
        continue;
    }
    const nameLower = name.toLowerCase();
    const isKnown = knownLower.some(p => {
        const parts = p.split(' ');
        return parts.some(part => part.length > 2 && nameLower.includes(part));
    });
    speakerMap[label] = isKnown ? name : label;
}

const mapEntries = Object.entries(speakerMap).map(([k, v]) => `${k} = ${v}`).join(', ');
const speakerComment = `<!-- Speaker map: ${mapEntries} -->`;

// Apply speaker names to transcript
let resolvedTranscript = transcriptFull;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll(`[${label}]`, `[${name}]`);
}

// Slice transcript by timestamps
const lines = resolvedTranscript.split('\n');

function timeToSeconds(timeStr) {
    const parts = timeStr.trim().split(':');
    if (parts.length === 3) return parseFloat(parts[0])*3600 + parseFloat(parts[1])*60 + parseFloat(parts[2]);
    if (parts.length === 2) return parseFloat(parts[0])*60 + parseFloat(parts[1]);
    return parseFloat(timeStr) || 0;
}

const lineTimestamps = [];
let lastTimestamp = 0;
const tsRegex = /\[(\d[\d:.]+)\s*(?:-->|->|\u2013|\u2014|-)\s*(\d[\d:.]+)\]/;
for (const line of lines) {
    const match = line.match(tsRegex);
    if (match) lastTimestamp = timeToSeconds(match[1]);
    lineTimestamps.push({line, timestamp: lastTimestamp});
}

const topicItems = [];
for (let i = 0; i < topics.length; i++) {
    const topic = topics[i];
    const tStart = topic.start || 0;
    const tEnd = topic.end || 999999;
    const topicLines = lineTimestamps
        .filter(lt => lt.timestamp >= tStart && lt.timestamp <= tEnd)
        .map(lt => lt.line);
    const topicTranscript = topicLines.join('\n');

    topicItems.push({
        json: {
            topicIndex: i,
            topicName: topic.name,
            topicSummary: topic.summary || '',
            topicTranscript: topicTranscript,
            totalTopics: topics.length,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
            topicsFallback: topicsFallback,
        }
    });
}

// Catch orphaned lines past last topic
if (topicItems.length > 0) {
    const coveredMax = Math.max(...topics.map(t => t.end || 0));
    const orphanLines = lineTimestamps
        .filter(lt => lt.timestamp > coveredMax)
        .map(lt => lt.line)
        .filter(l => l.trim());
    if (orphanLines.length > 0) {
        const lastItem = topicItems[topicItems.length - 1];
        lastItem.json.topicTranscript += '\n' + orphanLines.join('\n');
    }
}

if (topicItems.length === 0) {
    topicItems.push({
        json: {
            topicIndex: 0,
            topicName: 'Full Meeting',
            topicSummary: 'Complete meeting discussion',
            topicTranscript: resolvedTranscript,
            totalTopics: 1,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
            topicsFallback: true,
        }
    });
}

return topicItems;

const item = $input.item.json;
const bodyObj = JSON.parse(item.body);

// Call Ollama via n8n built-in HTTP helper
const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/generate',
    body: bodyObj,
    headers: {'Content-Type': 'application/json'},
    timeout: 600000,
    returnFullResponse: false,
    json: true,
});

return {
    json: {
        response: result.response || '',
        topicIndex: item.topicIndex,
        topicName: item.topicName,
        totalTopics: item.totalTopics,
    }
};

const items = $input.all();

// Get metadata from first item's input
const firstInput = $('Slice Topics').first().json;
const date = firstInput.date;
const meetingName = firstInput.meetingName;
const startTime = firstInput.startTime;
const endTime = firstInput.endTime;
const participantStr = firstInput.participantStr;
const speakerComment = firstInput.speakerComment;
const speakerMap = firstInput.speakerMap || {};
const context = firstInput.context || '';

// ── Name normalization ──
// participantStr contains CANONICAL names (already Lastname Firstname from webhook)
// e.g. "Rantala Petri, Kasi Jukka"
const participantNames = participantStr.split(',').map(p => p.trim()).filter(Boolean);

// Build reversed→canonical mapping: "Petri Rantala" → "Rantala Petri"
const nameNormMap = {};
for (const canonical of participantNames) {
    const parts = canonical.split(/\s+/);
    if (parts.length >= 2) {
        // canonical is "Rantala Petri" (Lastname Firstname)
        // reversed is "Petri Rantala" (Firstname Lastname — what LLM writes)
        const reversed = parts.slice(1).join(' ') + ' ' + parts[0];
        nameNormMap[reversed] = canonical;
        // identity mapping so canonical stays canonical
        nameNormMap[canonical] = canonical;
    }
}

// Build attendees directly from canonical participant names
const attendees = new Set();
for (const canonical of participantNames) {
    attendees.add(`[[${canonical}]]`);
}
// Also add biometric-matched names from speaker map if not covered
for (const name of Object.values(speakerMap)) {
    if (name && name !== 'Unknown' && !name.startsWith('SPEAKER_')) {
        const alreadyCovered = [...attendees].some(a => {
            const inner = a.replace(/^\[\[|\]\]$/g, '');
            const nameParts = name.split(/\s+/);
            return nameParts.every(p => inner.toLowerCase().includes(p.toLowerCase()));
        });
        if (!alreadyCovered) {
            attendees.add(`[[${name}]]`);
        }
    }
}
const attendeeLines = [...attendees].map(a => `- [x] ${a}`).join('\n');

// Sort topic results by index
const sorted = items.map(i => ({
    index: i.json.topicIndex || 0,
    name: i.json.topicName || 'Topic',
    content: i.json.response || '',
})).sort((a, b) => a.index - b.index);

// Build descriptive meeting summary
const summaryLines = sorted.map(t => {
    const lines = (t.content || '').split('\n');
    const desc = lines.find(l => l.trim() && !l.startsWith('#') && !l.startsWith('<') && !l.startsWith('**Key') && !l.startsWith('**Outcome'));
    return `- **${t.name}:** ${desc || t.name}`;
}).join('\n');

// Build agenda with wikilinks to headings
const agenda = sorted.map(t => `- [[#${t.name}]]`).join('\n');

// Build notes body from all topic analyses
let notesBody = sorted.map(t => t.content).join('\n\n');

// ── Normalize names: [[Firstname Lastname]] → [[Lastname Firstname]] ──
for (const [fromName, toName] of Object.entries(nameNormMap)) {
    if (fromName !== toName) {
        // Wikilinked mentions
        notesBody = notesBody.replaceAll(`[[${fromName}]]`, `[[${toName}]]`);
        // Plain text mentions (not inside wikilinks)
        const escapedFrom = fromName.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
        notesBody = notesBody.replace(new RegExp(`(?<!\\[\\[)\\b${escapedFrom}\\b(?!\\]\\])`, 'g'), toName);
    }
}

// ── Aggressive instruction echo removal ──
// Remove multi-line prompt template blocks that LLM echoed verbatim
// Pattern: "IF a concrete decision..." through "...OMIT the #### ACTION ITEMS section..."
notesBody = notesBody.replace(/IF a concrete decision was made[\s\S]*?OMIT the ####\s*ACTION ITEMS section[^\n]*\n?/gi, '');

// Catch partial echoes of the DECISION/ACTION template
notesBody = notesBody.replace(/IF NO decision was made[\s\S]*?Do NOT write "No decision"[^\n]*\n?/gi, '');
notesBody = notesBody.replace(/IF NO action items exist[\s\S]*?Do NOT write "No action items"[^\n]*\n?/gi, '');
notesBody = notesBody.replace(/IF concrete action items or follow-ups[\s\S]*?<emoji>[^\n]*\n?/gi, '');

// Standalone single-line echoes (when LLM echoes just the instruction line without the full block)
notesBody = notesBody.replace(/^IF a concrete decision was made[^\n]*include:\s*$/gm, '');
notesBody = notesBody.replace(/^IF concrete action items or follow-ups were agreed[^\n]*include:\s*$/gm, '');
notesBody = notesBody.replace(/^IF NO decision was made[^\n]*$/gm, '');
notesBody = notesBody.replace(/^IF NO action items[^\n]*$/gm, '');
notesBody = notesBody.replace(/^OMIT the ####[^\n]*$/gm, '');
notesBody = notesBody.replace(/^Do NOT write "No decision[^\n]*$/gm, '');
notesBody = notesBody.replace(/^Do NOT write "No action items[^\n]*$/gm, '');

// Remove echoed attribution instructions
notesBody = notesBody.replace(/^.*Attribute key points to the speaker who made them[^\n]*\n?/gm, '');
notesBody = notesBody.replace(/^.*Do NOT include raw transcript timestamps[^\n]*\n?/gm, '');
notesBody = notesBody.replace(/^.*instead weave attribution naturally[^\n]*\n?/gm, '');
notesBody = notesBody.replace(/^.*Do NOT list action items here[^\n]*\n?/gm, '');

// Remove echoed RULES: blocks (everything from RULES: to next ### or **)
notesBody = notesBody.replace(/^RULES:\n(?:- .*\n?)*/gm, '');

// Remove echoed format instructions
notesBody = notesBody.replace(/^.*Write ONE sentence summarizing[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*use EXACT format[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*REPLACE this instruction with[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*<one sentence summarizing the outcome[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Output must be in this exact markdown format[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*List 3-7 concrete bullets[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Every action item line MUST start with[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*SPEAKERS: ONLY the people in the Participants[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Do NOT invent facts[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*NAME SPELLING: Use exact name spellings[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Names MUST be \[\[Lastname Firstname\]\][^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Use complexity emoji inline[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Calculate the actual date\. Never[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Meeting date: \d{4}-\d{2}-\d{2}[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Language: Business American English[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*\*\*When:\*\* If a specific deadline[^\n]*$/gm, '');
notesBody = notesBody.replace(/^.*Only create action items for REAL commitments[^\n]*$/gm, '');
notesBody = notesBody.replace(/^\s*🟩 Easy → meeting date \+ 3 days[^\n]*$/gm, '');
notesBody = notesBody.replace(/^\s*🟨 Involved → meeting date \+ 7 days[^\n]*$/gm, '');
notesBody = notesBody.replace(/^\s*🟧 Moderate → meeting date \+ 14 days[^\n]*$/gm, '');
notesBody = notesBody.replace(/^\s*🟥 Hard → meeting date \+ 30 days[^\n]*$/gm, '');

// Remove "Write exactly one of:" outcome instruction echoes
notesBody = notesBody.replace(/^\*\*Outcome:\*\*\s*Write exactly one of[^\n]*$/gm, '');

// Remove empty DECISION blocks
notesBody = notesBody.replace(/####\s*DECISION\s*\n\*\*What:\*\*\s*(?:No decision[^.\n]*\.?|describe the decision concisely|N\/A|None|—|-)\s*\n?/gi, '');

// Remove empty ACTION ITEMS blocks
notesBody = notesBody.replace(/####\s*ACTION ITEMS\s*\n(?:\s*(?:No action items?[^.\n]*\.?|N\/A|None|—|-)\s*\n?)+/gi, '');

// Remove duplicate topic sections (same ### heading appearing twice — second is usually the echoed version)
const seenHeadings = new Set();
const lines = notesBody.split('\n');
const filteredLines = [];
let skipping = false;
for (let i = 0; i < lines.length; i++) {
    const headingMatch = lines[i].match(/^###\s+(.+)$/);
    if (headingMatch) {
        // Normalize: collapse repeated consecutive words ("organizational organizational" → "organizational")
        const heading = headingMatch[1].trim().toLowerCase().replace(/\b(\w+)\s+\1\b/gi, '$1');
        if (seenHeadings.has(heading)) {
            // Skip this duplicate section until next ## or ###
            skipping = true;
            continue;
        }
        seenHeadings.add(heading);
        skipping = false;
    } else if (skipping) {
        // Check if we hit a new section that's NOT a duplicate
        if (lines[i].match(/^##[^#]/)) {
            skipping = false;
        } else if (lines[i].match(/^###\s+/) && !seenHeadings.has(lines[i].replace(/^###\s+/, '').trim().toLowerCase().replace(/\b(\w+)\s+\1\b/gi, '$1'))) {
            skipping = false;
        } else {
            continue;
        }
    }
    filteredLines.push(lines[i]);
}
notesBody = filteredLines.join('\n');

// Fix doubled labels
notesBody = notesBody.replace(/\*\*WhenWhen:\*\*/g, '**When:**');
notesBody = notesBody.replace(/\*\*WhatWhat:\*\*/g, '**What:**');
notesBody = notesBody.replace(/\*\*WhoWho:\*\*/g, '**Who:**');

// Fix LLM garbling: repeated consecutive words (e.g. "from from" → "from", "made made" → "made")
notesBody = notesBody.replace(/\b(\w{3,})\s+\1\b/gi, '$1');
// Fix garbled speaker references like 'shared shareds="Kasi Jukka"'
notesBody = notesBody.replace(/\w+eds?="[^"]*"\s*/g, '');
// Fix doubled names like "Paul Paul Pompeen" → "Paul Pompeen"
notesBody = notesBody.replace(/\b(\w+)\s+\1\s+(\w)/g, '$1 $2');
// Fix doubled suffixes like "discusseded" → "discussed"
notesBody = notesBody.replace(/(\w+)eded\b/g, '$1ed');

// Normalize action item format — ensure ***Action Point:*** prefix
notesBody = notesBody.replace(/^- \[ \]\s+(?!\*\*\*Action Point:\*\*\*)(🟩|🟨|🟧|🟥)/gm,
    '- [ ] ***Action Point:*** $1');

// Fix action items missing leading "- " (bare [ ] lines)
notesBody = notesBody.replace(/^\[ \]\s+\*\*\*Action Point:\*\*\*/gm,
    '- [ ] ***Action Point:***');

// Strip complexity emojis from key point lines (only belong on action items)
notesBody = notesBody.replace(/^(- (?!\[ \]))(\s*)(🟩|🟨|🟧|🟥)\s*/gm, '$1$2');

// Remove **Key:** (truncated header — should be **Key Points:**)
notesBody = notesBody.replace(/^\*\*Key:\*\*$/gm, '**Key Points:**');

// Collapse 3+ consecutive blank lines to 2
notesBody = notesBody.replace(/\n{3,}/g, '\n\n');

// Trim trailing whitespace on each line
notesBody = notesBody.split('\n').map(l => l.trimEnd()).join('\n');

